        ctx.globalAlpha = 0.3;
        let ghostX = snake === player ? 5 : COLS - 6;
        let ghostY = Math.floor(ROWS / 2);
        ctx.fillStyle = snake.color;
        ctx.fillRect(ghostX * GRID + 2, ghostY * GRID + 2, GRID - 4, GRID - 4);
        ctx.globalAlpha = 1;
        // Draw respawn countdown
        ctx.fillStyle = 'white';
        ctx.font = '12px Arial';
        ctx.textAlign = 'center';
        ctx.fillText(Math.ceil(snake.respawnTimer), ghostX * GRID + GRID/2, ghostY * GRID + GRID/2 + 4);
        return;
    }

    for (let i = snake.body.length - 1; i >= 0; i--) {
        let seg = snake.body[i];
        let x = seg.x * GRID;
        let y = seg.y * GRID;

        if (i === 0) {
            // Head
            ctx.fillStyle = snake.headColor;
            ctx.shadowColor = snake.headColor;
            ctx.shadowBlur = 10;
            ctx.beginPath();
            ctx.roundRect(x + 1, y + 1, GRID - 2, GRID - 2, 5);
